def initials(name: str) -> str:
    """Return the upper-case initials of each word in `name`, e.g. 'ada lovelace' -> 'AL'."""
    return ''.join(word[0].upper() for word in name.split() if word)

# Usage: initials('ada lovelace')  # -> 'AL'
